CODE_EXAMPLE:
// Before
class Dog {
  String name;
  void display() { ... }
}

class Cat {
  String name;
  void display() { ... }
}

// After
class Animal {
  String name;
  void display() { ... }
}

class Dog extends Animal {}
class Cat extends Animal {}

UNIT_TEST_EXAMPLE:
@Test
public void testExtractSuperclass() {
  Animal dog = new Dog();
  dog.setName("Buddy");
  assertEquals("Buddy", dog.getName());
}
